public void testNumberOverflowIntNegative() throws IOException
{
    final long tooSmall = -1L + Integer.MIN_VALUE;
    try (final JsonParser p = MAPPER.readTree("[ "+tooSmall+" ]").traverse()) {
        assertToken(JsonToken.START_ARRAY, p.nextToken());
        assertToken(JsonToken.VALUE_NUMBER_INT, p.nextToken());
        assertEquals(NumberType.LONG, p.getNumberType());
        try {
            p.getIntValue();
            fail("Expected failure for `int` underflow");
        } catch (InputCoercionException e) {
            verifyException(e, "Numeric value ("+tooSmall+") out of range of int");
        }
    }
}

public void testNumberOverflowLongNegative() throws IOException
{
    final BigInteger tooSmall = BigInteger.valueOf(Long.MIN_VALUE).subtract(BigInteger.ONE);
    try (final JsonParser p = MAPPER.readTree("[ "+tooSmall+" ]").traverse()) {
        assertToken(JsonToken.START_ARRAY, p.nextToken());
        assertToken(JsonToken.VALUE_NUMBER_INT, p.nextToken());
        assertEquals(NumberType.BIG_INTEGER, p.getNumberType());
        try {
            p.getLongValue();
            fail("Expected failure for `long` underflow");
        } catch (InputCoercionException e) {
            verifyException(e, "Numeric value ("+tooSmall+") out of range of long");
        }
    }
}

public void testNumberValidIntFromLong() throws IOException
{
    final long validInt = Integer.MAX_VALUE;
    try (final JsonParser p = MAPPER.readTree("[ "+validInt+" ]").traverse()) {
        assertToken(JsonToken.START_ARRAY, p.nextToken());
        assertToken(JsonToken.VALUE_NUMBER_INT, p.nextToken());
        assertEquals(NumberType.LONG, p.getNumberType());
        assertEquals((int)validInt, p.getIntValue());
    }
}
